"""Minimal RAG loop using MemKraft search."""
from memkraft import MemKraft

mk = MemKraft(base_dir="./memory")

def retrieve(query: str, k: int = 5):
    results = mk.search(query, fuzzy=True) or []
    return results[:k]

if __name__ == "__main__":
    hits = retrieve("example query")
    for h in hits:
        print(h)
